css:
.top {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    width: 100%;
    gap: 10px;

}

.top-left {
    flex: 0 0 60%;
    max-width: 60%;
}

.top-right {
    flex: 0 0 40%;
    max-width: 40%;
    text-align: right;
    display: flex;
    align-items: flex-start;
    flex-direction: column;

    gap: 8px;   /* ← controls vertical spacing */
}
.totals {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    width: 100%;
    gap: 10px;
    margin-top: 10%;
}

.totals-left {
    flex: 0 0 60%;
    max-width: 60%;
}

.totals-right {
    flex: 0 0 40%;
    max-width: 40%;
    text-align: right;
    display: flex;
    align-items: flex-start;
    flex-direction: column;
    gap: 8px;   /* ← controls vertical spacing */
}
.title-p {
    font-weight: bold;
    color: gray;

}
.items-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 11px;
}

.items-table th,.items-table td {
    border: none !important;
    padding: 6px 4px;
    vertical-align: middle;
}

.items-table thead th {
    font-weight: bold;
}

.text-right {
    text-align: right;
}

.text-center {
    text-align: center;
}
.section-divider {
    border-top: 1px solid #ccc;

}
.double-line-section {

}

.double-line-section .line {
    height: 1px;
    background: #f2f2f2;   /* change to #ccc if you want lighter */
    margin: 5px 0;
}

.due-amount {
    margin: 4px 0;
    font-size: 12px;
}
.due-highlight {
    background-color: #f2f2f2;   /* soft grey */
    padding: 6px 8px;
    margin-top: 6px;
    border-radius: 4px;          /* subtle modern touch */
    font-weight: bold;
}
.description{
       color: gray;
       margin-top:20px;
}
.description-text{
    width:50%;
}
.dotted-line {
    border-top: 2px dotted #000000;
    margin: 10px 0;
    width:50%;
}
